Modified greedy insertion with incremental cost evaluation across all assign slots using best-first search per order, preserving original assign states via copy-on-trial.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type slotCandidate struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	fallbackSlot := func(j int) {
		newIdx := dispatch.AssignsLen
		if newIdx < MAXASSIGNS {
			dispatch.Assigns[newIdx].AddShip(total_ship+j, oris[j], dess[j])
			dispatch.Assigns[newIdx].GenRoute()
			dispatch.AssignsLen++
		}
	}
	for j := range oris {
		bestCand := slotCandidate{-1, 0, false}
		baseCostBackup := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			baseCostBackup[i] = dispatch.Assigns[i].Cost
		}
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].AddShip(total_ship+j, oris[j], dess[j]) {
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 {
					delta := dispatch.Assigns[i].Cost - baseCostBackup[i]
					if !bestCand.ok || delta < bestCand.costDelta {
						bestCand.assignIdx = i
						bestCand.costDelta = delta
						bestCand.ok = true
					}
				}
				dispatch.Assigns[i].RemoveShip(total_ship + j)
				dispatch.Assigns[i].Cost = baseCostBackup[i]
				dispatch.Assigns[i].GenRoute()
			}
		}
		if bestCand.ok {
			dispatch.Assigns[bestCand.assignIdx].AddShip(total_ship+j, oris[j], dess[j])
			dispatch.Assigns[bestCand.assignIdx].GenRoute()
		} else {
			succeeded := false
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].AddShip(total_ship+j, oris[j], dess[j]) {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						succeeded = true
						break
					}
					dispatch.Assigns[i].RemoveShip(total_ship + j)
					dispatch.Assigns[i].GenRoute()
				}
			}
			if !succeeded {
				fallbackSlot(j)
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

